import{_ as a,o as r,c as l,a2 as o}from"./chunks/framework.Bjylvv1V.js";const g=JSON.parse('{"title":"연말정산 처리","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/year-end-tax.md","filePath":"guide/scenarios/year-end-tax.md","lastUpdated":null}'),e={name:"guide/scenarios/year-end-tax.md"};function i(s,t,n,d,h,c){return r(),l("div",null,[...t[0]||(t[0]=[o(`<h1 id="연말정산-처리" tabindex="-1">연말정산 처리 <a class="header-anchor" href="#연말정산-처리" aria-label="Permalink to &quot;연말정산 처리&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 약 3시간 (전체 직원) | <strong>난이도</strong>: ★★★ | <strong>주기</strong>: 연 1회 (1~2월)</p></blockquote><p>매년 1~2월에 직원의 연간 근로소득에 대한 소득세를 정산하고, 홈택스에 전자 신고하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 연말정산기본정보 등록   (5분)   → 연도·사업자번호·세액 기준 확인</span></span>
<span class="line"><span>2. 전직장내역 등록         (건당)  → 중도 입사자의 전직장 원천징수 영수증 입력</span></span>
<span class="line"><span>3. 연근로소득내역 등록     (10분)  → 연간 총급여·비과세·상여 확인</span></span>
<span class="line"><span>4. 개인공제자료 등록       (건당)  → 부양가족·보험·연금·의료비·기부금·월세 입력</span></span>
<span class="line"><span>5. 연말정산 작업 실행      (5분)   → 최종 세액 자동 계산</span></span>
<span class="line"><span>6. 결과 조회               (10분)  → 원천징수영수증 확인 및 출력</span></span>
<span class="line"><span>7. 정산디스켓 작성         (5분)   → 홈택스 전자신고 파일 생성</span></span>
<span class="line"><span>8. 징수환차/환급금 처리    (5분)   → 다음 급여에 반영</span></span></code></pre></div><hr><h2 id="사전-준비" tabindex="-1">사전 준비 <a class="header-anchor" href="#사전-준비" aria-label="Permalink to &quot;사전 준비&quot;">​</a></h2><h3 id="직원에게-안내할-사항" tabindex="-1">직원에게 안내할 사항 <a class="header-anchor" href="#직원에게-안내할-사항" aria-label="Permalink to &quot;직원에게 안내할 사항&quot;">​</a></h3><p>연말정산 시작 전에 직원에게 다음을 안내합니다:</p><ul><li>홈택스에서 소득·세액공제자료 PDF 다운로드 방법 <ul><li>경로: 홈택스(www.hometax.go.kr) &gt; 조회/발급 &gt; 연말정산 &gt; 소득·세액공제자료 조회 &gt; PDF로 내려받기</li><li><strong>반드시 비밀번호 없이</strong> 다운로드</li></ul></li><li>부양가족 주민번호 확인 (등록 시 필요)</li><li>전직장 원천징수영수증 (중도 입사자 해당)</li></ul><hr><h2 id="_1단계-연말정산기본정보-등록-5분" tabindex="-1">1단계: 연말정산기본정보 등록 (5분) <a class="header-anchor" href="#_1단계-연말정산기본정보-등록-5분" aria-label="Permalink to &quot;1단계: 연말정산기본정보 등록 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/year-end.html">연말정산</a> &gt; 연말정산기본정보</p></blockquote><ol><li>정산 <strong>연도</strong> 확인 (예: 2025년 귀속)</li><li>사업자번호, 단지명 확인</li><li>세액 계산 기준 설정</li><li><strong>저장</strong> 클릭</li></ol><hr><h2 id="_2단계-전직장내역-등록-중도-입사자만" tabindex="-1">2단계: 전직장내역 등록 (중도 입사자만) <a class="header-anchor" href="#_2단계-전직장내역-등록-중도-입사자만" aria-label="Permalink to &quot;2단계: 전직장내역 등록 (중도 입사자만)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/year-end.html">연말정산</a> &gt; 전직장내역등록 (PAY4020)</p></blockquote><p>당해 연도 중에 입사한 직원의 전직장 급여·세액 정보를 입력합니다.</p><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>전직장내역등록 화면 진입</li><li>해당 직원 선택</li><li>전직장에서 수령한 원천징수영수증 기준으로 입력:</li></ol><table tabindex="0"><thead><tr><th>입력 항목</th><th>설명</th></tr></thead><tbody><tr><td>전직장 근무 기간</td><td>입사일 ~ 퇴사일</td></tr><tr><td>총급여액</td><td>전직장 총 급여</td></tr><tr><td>비과세소득</td><td>식대 등 비과세 항목</td></tr><tr><td>기납부 세액</td><td>전직장에서 납부한 소득세·지방소득세</td></tr></tbody></table><ol start="4"><li><strong>저장</strong> 클릭</li></ol><div class="warning custom-block"><p class="custom-block-title">중도 입사자 필수</p><p>전직장내역을 입력하지 않으면 해당 연도 전체 소득 합산이 되지 않아 정산이 부정확합니다.</p></div><hr><h2 id="_3단계-연근로소득내역-등록-10분" tabindex="-1">3단계: 연근로소득내역 등록 (10분) <a class="header-anchor" href="#_3단계-연근로소득내역-등록-10분" aria-label="Permalink to &quot;3단계: 연근로소득내역 등록 (10분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/year-end.html">연말정산</a> &gt; 연근로소득내역등록 (PAY4010)</p></blockquote><p>시스템에서 계산된 연간 급여 내역을 확인하고, 필요 시 조정합니다.</p><h3 id="확인-항목" tabindex="-1">확인 항목 <a class="header-anchor" href="#확인-항목" aria-label="Permalink to &quot;확인 항목&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>설명</th></tr></thead><tbody><tr><td>총급여액</td><td>연간 총 지급 급여</td></tr><tr><td>비과세소득</td><td>식대(월 20만 원 이내) 등</td></tr><tr><td>상여금</td><td>연간 지급 상여 합계</td></tr><tr><td>기납부 세액</td><td>매월 원천징수한 소득세·지방소득세 합계</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">자동 반영</p><p>월별 급여 계산을 정상적으로 진행했다면 대부분의 항목이 <strong>자동 집계</strong>됩니다. 누락이나 수정 사항이 있는 경우에만 직접 수정합니다.</p></div><hr><h2 id="_4단계-개인공제자료-등록-건당-10-20분" tabindex="-1">4단계: 개인공제자료 등록 (건당 10~20분) <a class="header-anchor" href="#_4단계-개인공제자료-등록-건당-10-20분" aria-label="Permalink to &quot;4단계: 개인공제자료 등록 (건당 10~20분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/year-end.html">연말정산</a> &gt; 개인공제자료등록 (PAY4030)</p></blockquote><p>직원별로 소득·세액공제 자료를 입력합니다.</p><h3 id="홈택스-pdf-자동-업로드" tabindex="-1">홈택스 PDF 자동 업로드 <a class="header-anchor" href="#홈택스-pdf-자동-업로드" aria-label="Permalink to &quot;홈택스 PDF 자동 업로드&quot;">​</a></h3><p>가장 빠른 방법으로, 직원이 제출한 홈택스 PDF 파일을 업로드하여 자동 입력합니다.</p><ol><li>개인공제자료등록 화면 진입</li><li>해당 직원 선택</li><li><strong>홈택스 PDF 올리기</strong> 버튼 클릭</li><li>직원이 제출한 PDF 파일 선택</li><li>자동 반영 확인</li></ol><div class="danger custom-block"><p class="custom-block-title">PDF 비밀번호 설정 금지</p><p>홈택스에서 PDF를 다운로드할 때 <strong>비밀번호를 설정하면 업로드가 불가</strong>합니다. 직원에게 비밀번호 없이 다운로드하도록 반드시 안내하세요.</p></div><div class="warning custom-block"><p class="custom-block-title">자동 반영 후 검토 필수</p><p>PDF 업로드 후에도 <strong>각 항목을 직접 확인</strong>하세요. 자동 반영이 정확하지 않을 수 있습니다.</p></div><h3 id="공제-항목별-입력" tabindex="-1">공제 항목별 입력 <a class="header-anchor" href="#공제-항목별-입력" aria-label="Permalink to &quot;공제 항목별 입력&quot;">​</a></h3><p>PDF 업로드가 어렵거나 추가 항목이 있는 경우 직접 입력합니다:</p><table tabindex="0"><thead><tr><th>공제 항목</th><th>주요 입력 내용</th></tr></thead><tbody><tr><td><strong>부양가족</strong></td><td>가족관계, 주민번호, 소득 여부</td></tr><tr><td><strong>보험료</strong></td><td>건강보험, 생명보험, 자동차보험 등</td></tr><tr><td><strong>연금저축</strong></td><td>개인연금, IRP 납입액</td></tr><tr><td><strong>의료비</strong></td><td>본인·부양가족 의료비 지출액</td></tr><tr><td><strong>교육비</strong></td><td>자녀 교육비 (학원비 제외)</td></tr><tr><td><strong>기부금</strong></td><td>법정·지정 기부금</td></tr><tr><td><strong>신용카드</strong></td><td>신용카드·현금영수증·체크카드 사용액</td></tr><tr><td><strong>주택자금</strong></td><td>주택청약·전세대출 이자 등</td></tr><tr><td><strong>월세</strong></td><td>월세 납부액 (세액공제 요건 확인)</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">부양가족 주민번호 미입력 시</p><p>부양가족 주민번호를 입력하지 않으면 <strong>&quot;일치하는 부양인 없음&quot;</strong> 으로 표시되어 공제가 적용되지 않습니다. 반드시 주민번호를 확인하여 입력하세요.</p></div><hr><h2 id="_5단계-연말정산-작업-실행-5분" tabindex="-1">5단계: 연말정산 작업 실행 (5분) <a class="header-anchor" href="#_5단계-연말정산-작업-실행-5분" aria-label="Permalink to &quot;5단계: 연말정산 작업 실행 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/year-end.html">연말정산</a> &gt; 연말정산작업 (PAY4040)</p></blockquote><p>입력된 공제 자료를 바탕으로 최종 세액을 계산합니다.</p><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>연말정산작업 화면 진입</li><li>정산 연도 확인</li><li>대상 직원 선택 (전체 또는 개별)</li><li><strong>계산 실행</strong> 클릭</li><li>계산 완료 확인</li></ol><div class="tip custom-block"><p class="custom-block-title">특별소득공제 vs 표준세액공제 자동 선택</p><p>XpERP가 특별소득공제와 표준세액공제 중 <strong>직원에게 유리한 방향을 자동으로 계산</strong>합니다. 별도로 선택할 필요가 없습니다.</p></div><hr><h2 id="_6단계-결과-조회-및-원천징수영수증-출력-10분" tabindex="-1">6단계: 결과 조회 및 원천징수영수증 출력 (10분) <a class="header-anchor" href="#_6단계-결과-조회-및-원천징수영수증-출력-10분" aria-label="Permalink to &quot;6단계: 결과 조회 및 원천징수영수증 출력 (10분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/year-end.html">연말정산</a> &gt; 연말정산결과조회 (PAY4041)</p></blockquote><h3 id="절차-2" tabindex="-1">절차 <a class="header-anchor" href="#절차-2" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>연말정산결과조회 화면 진입</li><li>직원별 정산 결과 확인:</li></ol><table tabindex="0"><thead><tr><th>확인 항목</th><th>내용</th></tr></thead><tbody><tr><td>결정세액</td><td>최종 납부해야 할 소득세</td></tr><tr><td>기납부세액</td><td>이미 납부한 소득세 합계</td></tr><tr><td><strong>차감징수세액</strong></td><td>(+) 추가 납부 / (-) 환급</td></tr></tbody></table><ol start="3"><li>이상 없으면 <strong>근로소득원천징수영수증</strong> 출력</li><li>직원에게 교부</li></ol><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 모든 직원의 정산 결과가 조회되는가?</li><li>[ ] 결정세액이 합리적인가?</li><li>[ ] 과다 환급이나 과다 추징 건은 없는가?</li></ul><hr><h2 id="_7단계-정산디스켓-작성-5분" tabindex="-1">7단계: 정산디스켓 작성 (5분) <a class="header-anchor" href="#_7단계-정산디스켓-작성-5분" aria-label="Permalink to &quot;7단계: 정산디스켓 작성 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/year-end.html">연말정산</a> &gt; 정산디스켓작성 (PAY4050)</p></blockquote><p>국세청 홈택스에 전자 신고할 파일을 생성합니다.</p><h3 id="절차-3" tabindex="-1">절차 <a class="header-anchor" href="#절차-3" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>정산디스켓작성 화면 진입</li><li>정산 연도 및 대상 직원 확인</li><li><strong>파일 생성</strong> 클릭</li><li>저장 경로 지정 후 저장</li><li>홈택스(www.hometax.go.kr)에 접속하여 파일 업로드 제출</li></ol><div class="danger custom-block"><p class="custom-block-title">제출 기한: 2월 말</p><p>연말정산 지급명세서 홈택스 제출 기한은 <strong>매년 2월 말</strong>입니다. 기한을 초과하면 가산세가 부과됩니다.</p></div><hr><h2 id="_8단계-징수환차-환급금-처리-5분" tabindex="-1">8단계: 징수환차/환급금 처리 (5분) <a class="header-anchor" href="#_8단계-징수환차-환급금-처리-5분" aria-label="Permalink to &quot;8단계: 징수환차/환급금 처리 (5분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 인사/급여 &gt; <a href="/pay/year-end.html">연말정산</a> &gt; 징수환차/환급금 (PAY4060)</p></blockquote><p>연말정산 결과를 다음 달 급여에 반영합니다.</p><h3 id="절차-4" tabindex="-1">절차 <a class="header-anchor" href="#절차-4" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>징수환차/환급금 화면 진입</li><li>직원별 추가 징수 또는 환급 금액 확인</li><li>반영 월(급여 지급월) 설정</li><li><strong>급여 반영</strong> 처리 클릭</li></ol><h3 id="반영-방식" tabindex="-1">반영 방식 <a class="header-anchor" href="#반영-방식" aria-label="Permalink to &quot;반영 방식&quot;">​</a></h3><table tabindex="0"><thead><tr><th>구분</th><th>처리 방법</th></tr></thead><tbody><tr><td><strong>추가 징수</strong></td><td>다음 달 급여에서 추가 공제</td></tr><tr><td><strong>환급</strong></td><td>다음 달 급여에 합산 지급</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">분할 납부</p><p>추가 징수 금액이 큰 경우, 직원 동의 하에 분할하여 수개월에 걸쳐 공제할 수 있습니다.</p></div><hr><h2 id="연말정산-체크리스트" tabindex="-1">연말정산 체크리스트 <a class="header-anchor" href="#연말정산-체크리스트" aria-label="Permalink to &quot;연말정산 체크리스트&quot;">​</a></h2><h3 id="진행-전" tabindex="-1">진행 전 <a class="header-anchor" href="#진행-전" aria-label="Permalink to &quot;진행 전&quot;">​</a></h3><ul><li>[ ] 직원에게 홈택스 PDF 제출 안내 완료</li><li>[ ] 전직장 원천징수영수증 수집 완료 (중도 입사자)</li><li>[ ] PDF 비밀번호 미설정 확인 안내 완료</li></ul><h3 id="진행-중" tabindex="-1">진행 중 <a class="header-anchor" href="#진행-중" aria-label="Permalink to &quot;진행 중&quot;">​</a></h3><ul><li>[ ] 전직장내역 등록 완료 (중도 입사자)</li><li>[ ] 연근로소득내역 확인 완료</li><li>[ ] 개인공제자료 입력 완료 (전 직원)</li><li>[ ] 연말정산 작업 실행 완료</li><li>[ ] 결과 검토 및 이상 여부 확인 완료</li></ul><h3 id="마무리" tabindex="-1">마무리 <a class="header-anchor" href="#마무리" aria-label="Permalink to &quot;마무리&quot;">​</a></h3><ul><li>[ ] 근로소득원천징수영수증 직원 교부 완료</li><li>[ ] 정산디스켓 홈택스 제출 완료 (2월 말 기한)</li><li>[ ] 징수/환급 다음 급여 반영 완료</li><li>[ ] 지급명세서 제출 완료 (3월 10일 기한)</li></ul><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="홈택스-pdf가-업로드되지-않아요" tabindex="-1">홈택스 PDF가 업로드되지 않아요 <a class="header-anchor" href="#홈택스-pdf가-업로드되지-않아요" aria-label="Permalink to &quot;홈택스 PDF가 업로드되지 않아요&quot;">​</a></h3><p><strong>원인</strong>: PDF에 비밀번호가 설정되어 있거나 파일이 손상된 경우 <strong>해결</strong>: 직원에게 홈택스에서 <strong>비밀번호 없이</strong> PDF를 다시 다운로드하도록 안내하세요. 경로: 홈택스 &gt; 조회/발급 &gt; 연말정산 &gt; 소득·세액공제자료 조회 &gt; PDF로 내려받기 (비밀번호 미설정)</p><h3 id="부양가족-공제가-적용되지-않아요" tabindex="-1">부양가족 공제가 적용되지 않아요 <a class="header-anchor" href="#부양가족-공제가-적용되지-않아요" aria-label="Permalink to &quot;부양가족 공제가 적용되지 않아요&quot;">​</a></h3><p><strong>원인</strong>: 부양가족 주민번호 미입력 또는 소득 기준 초과 <strong>해결</strong>: 부양가족의 주민번호를 입력하고, 해당 연도 소득 합계가 100만 원(근로소득만 있으면 총급여 500만 원) 이하인지 확인하세요.</p><h3 id="정산-결과-환급액이-지나치게-크거나-추징액이-과다해요" tabindex="-1">정산 결과 환급액이 지나치게 크거나 추징액이 과다해요 <a class="header-anchor" href="#정산-결과-환급액이-지나치게-크거나-추징액이-과다해요" aria-label="Permalink to &quot;정산 결과 환급액이 지나치게 크거나 추징액이 과다해요&quot;">​</a></h3><p><strong>원인</strong>: 공제 자료 중복 입력 또는 누락, 전직장내역 오류 <strong>해결</strong>: 개인공제자료등록(PAY4030)에서 각 항목을 다시 확인하고, 중도 입사자는 전직장내역(PAY4020)을 재검토하세요.</p><h3 id="디스켓-파일-제출-기한을-놓쳤어요" tabindex="-1">디스켓 파일 제출 기한을 놓쳤어요 <a class="header-anchor" href="#디스켓-파일-제출-기한을-놓쳤어요" aria-label="Permalink to &quot;디스켓 파일 제출 기한을 놓쳤어요&quot;">​</a></h3><p><strong>원인</strong>: 2월 말 기한 미준수 <strong>해결</strong>: 즉시 홈택스에 제출하세요. 기한 초과 시 가산세(미제출 건수 × 2만 원)가 부과됩니다.</p><hr><h2 id="주요-신고-기한" tabindex="-1">주요 신고 기한 <a class="header-anchor" href="#주요-신고-기한" aria-label="Permalink to &quot;주요 신고 기한&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>기한</th></tr></thead><tbody><tr><td>연말정산 디스켓 홈택스 제출</td><td><strong>2월 말</strong></td></tr><tr><td>근로소득 지급명세서 제출</td><td><strong>3월 10일</strong></td></tr><tr><td>원천징수 신고·납부 (정산 월)</td><td><strong>다음 달 10일</strong></td></tr></tbody></table><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/pay/year-end.html">연말정산</a> - 연말정산 전체 메뉴</li><li><a href="/pay/salary.html">급여관리</a> - 급여 기본정보, 급여 계산</li><li><a href="/pay/hr.html">인사관리</a> - 직원 기본정보</li><li><a href="/guide/scenarios/payroll.html">급여 처리</a> - 급여 처리 전체 프로세스</li><li><a href="/guide/scenarios/hr-manage.html">인사 관리</a> - 입퇴사 처리</li></ul>`,99)])])}const b=a(e,[["render",i]]);export{g as __pageData,b as default};
